const Q_ECONOMICS_2016=[{"id": "objective>Economics>2016>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the supply of a product is elastic, a small reduction in price will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase the quantity supplied</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the quantity supplied</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce the cost of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead to no change in the quantity supplied</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Elastic supply occurs when a little change in price brings about a more than proportional change in quantity supplied.increase in price will result to decrease in quantity supplied. <br/>  <br/> According to basic economic theory, the supply of a good will increase when its price rises. Conversely, the supply of a good will decrease when its price decreases. ... Overall, price elasticity measures how much the supply or demand of a product changes based on a given change in price.</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2016>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major role of multinational companies in the Nigeria petroleum industry is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oil marketing and prospecting</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishment of refineries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oil prospecting only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oil marketing only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Multi-national companies function in the area of oil marketing and prospecting. Examples are Mobil and Total.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>2016>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If P = 1/4(Qs + 10), what is the quantity supplied at ₦14?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">60</div>", "<div style=\"font-family:Cambria;font-size:17px;\">32</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14</div>", "<div style=\"font-family:Cambria;font-size:17px;\">46</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P = 1/4(Qs + 10), P = ₦14  <br/>  14 = 1/4(Qs + 10)  <br/>  56 = Qs + 10  <br/>  <br/>  Qs = 56 - 10  <br/>  = 46.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2016>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Import substitution policy is aimed at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">setting up local industries to produce goods formerly imported</div>", "<div style=\"font-family:Cambria;font-size:17px;\">setting up industries for regional development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">concentrating industries for even development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">banning the importation of goods locally produced</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Import substitution is a policy of industrialization by the government aimed at encouraging the local manufacturers to produce formerly imported goods. <br/> Import substitution industrialization (ISI) is a trade and economic policy which advocates replacing foreign imports with domestic production. ISI is based on the premise that a country should attempt to reduce its foreign dependency through the local production of industrialized products.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2016>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The short-run equilibrium point of a perfectly competitive firm is attained at a point where</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the marginal cost is equal to the price of the firm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the marginal cost curve is equal to the marginal revenue curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the demand curve is tangential to the marginal cost.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price is equal to total cost</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the short-run equilibrium of a perfectly competitive firm, the firm's marginal cost (MC) is equal to its marginal revenue (MR). This is because, in perfect competition, firms are price takers and can sell as much as they want at the market price. Therefore, they will produce up to the point where the cost of producing an additional unit (MC) is equal to the revenue gained from selling that additional unit (MR).</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2016>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country seeking loan for the correction of balance of payments problems will approach </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">IMF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IBRD</div>", "<div style=\"font-family:Cambria;font-size:17px;\">EEC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">OPEC</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">International Monetary Fund assist countries to correct Balance of payment deficits by giving them short term loans.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IMF"}, {"id": "objective>Economics>2016>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major factors militating against industrialization in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">frequent break-down of equipment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government participation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequacy of infrastructural facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low level of foreign investment</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Industrialization is the process by which an economy is transformed from primarily agricultural to one based on the manufacturing of goods. This process requires a significant amount of infrastructure, such as roads, ports, power plants, and other facilities. In Nigeria, there is a significant lack of these infrastructural facilities, which hinders the process of industrialization. Therefore, the correct answer is 'inadequacy of infrastructural facilities'.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2016>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the price of bicycle changes from ₦20 to ₦80 and the quantity bought change from 300 to 500 units, the elasticity of demand is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.22</div>", "<div style=\"font-family:Cambria;font-size:17px;\">66.70</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.00</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> = %Δ in Quantity demanded / %Δ in Price  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">%Δ</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">Quantity</td><td style=\"text-align:center;\">demanded</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500 - 300<hr size=\"1\" />300</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">%Δ</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">Quantity</td><td style=\"text-align:center;\">demanded</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200<hr size=\"1\" />300</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div>  <br/>  = 66.7  <br/>   <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">%Δ</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">Price</td><td style=\"text-align:center;\">.</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">80 - 20<hr size=\"1\" />20</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div> = 300  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">E<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">%Δ in Qd<hr size=\"1\" />%Δ in P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">66.7<hr size=\"1\" />300</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.22</td></tr></table></div></div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2016>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In order to add value to Nigeria agricultural produce, there is need to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">advertise them in European markets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adopt modern storage methods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">process them into finished goods</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cultivate high breed crops</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Adding value to agricultural produce often involves processing them into finished goods. This is because processing increases the usefulness of the product, enhances its aesthetic appeal, and makes it more marketable and profitable. Advertising them in European markets, adopting modern storage methods, and cultivating high breed crops are all important, but they do not directly add value to the produce in the same way that processing does.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2016>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A measure of national income used as a comparism of standard of living among nations is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">per capita income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gross national product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gross domestic product</div>", "<div style=\"font-family:Cambria;font-size:17px;\">net national product</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Per capita income reveals the average income of an individual. Hence, it shows the average income of an individual to the rest of the world.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2016>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> From the diagram above, the price elasticity of demand is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">perfectly elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fairly inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unitarily elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly inelastic</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram depicts a perfectly inelastic or zero elastic demand which implies that any change in price does not affect demand. i.e it is vertical to the y- axis</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2016>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the theory of consumer analysis, consumer equilibrium is reached at the point where the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">indifference curve is highest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">budget line is above the indifference curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indifference curve is tangential to the budget line</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indifference curve is lowest</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Consumer equilibrium is the point where the budget line is tangential to the indifference curve as shown below.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM"}, {"id": "objective>Economics>2016>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following set of statistical tools is used for further economic analysis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The median and standard deviation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mean and mode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mean and standard deviation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mode and median</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mean and standard deviation have proved to be useful for further statistical analysis e.g In estimating mean deviation or in the calculation of variance.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2016>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Life insurance companies contribute to economic development by holding a part of their assets in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">money-market instruments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equipment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">long-term financial instruments.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash and near money</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Life assurance basically keep peoples' asset in the form of long-term financial instrument since it has to do with life and the next of kin can always acquire such in the long term.</div>", "topic": "FINANCIAL INSTITUTION : INTRODUCTION"}, {"id": "objective>Economics>2016>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the goals of development plans in Nigeria is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">improve on the country's GDP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deregulates the economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the profitability of multinational businesses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">achieve higher standard of living for citizens</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Development plans at different times has the objective of achieving higher or improved standard of living for the masses e.g SURE-P etc.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2016>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the standard deviation of a given data is 53, what is the variance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2808</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2809</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2082</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2209</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If standard deviation is the square root of variance then variance is (53)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 2809.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2016>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is used by the Central Bank of Nigeria to control inflation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tax rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Discount rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tariffs on imports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Exchange rate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The CBN uses discount rate to control inflation. By increasing the discount rate, less money will be made available in the economy and vice-versa.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2016>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the selling price of a monopolist is below his short-run marginal cost, he is said to be making</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an economic profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">losses </div>", "<div style=\"font-family:Cambria;font-size:17px;\">supernormal profit</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In economics, when the selling price of a product is below its short-run marginal cost, the producer is said to be making losses. The short-run marginal cost is the cost of producing one more unit of a good or service after production has already started. If the selling price is below this cost, the producer is not covering the cost of production and is therefore making a loss.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2016>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the determinants of the price elasticity of supply is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">strength of taste established for the commodity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">availability of close substitutes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">level of income of consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ease of diversification of production</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The price elasticity of supply is determined by several factors, one of which is the ease of diversification of production. This refers to how easily a producer can switch from producing one good or service to another. If a producer can easily diversify their production, they can quickly respond to changes in price, making the supply more elastic. <br/>  <br/> Others include: the length of production period, the availability of spare capacity, market entry barriers, time scale, and the ease of accumulating stock.</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2016>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, efficiency in public corporations can be achieved through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">indigenization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nationalization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">public offer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">privatization</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Efficiency in public corporations can be achieved through privatization. Privatization is the process of transferring an enterprise or industry from the public sector to the private sector. The private sector, being profit-oriented, tends to run operations more efficiently due to competition and the desire for profitability.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>2016>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the price of a commodity will result in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in quantity demanded</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the quantity demanded</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in demand</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the law of demand, when the price of a commodity increases, the quantity demanded decreases, all other things being equal. This is because as the price of a commodity rises, consumers will tend to buy less of it and switch to cheaper substitutes.</div>", "topic": "THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND"}, {"id": "objective>Economics>2016>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Utility is the satisfaction derived from the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">use of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">production of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distribution of goods and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand for goods and services</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Utility in economics refers to the total satisfaction received from consuming a good or service. Therefore, the correct answer is 'use of goods and services'.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT"}, {"id": "objective>Economics>2016>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A valid explanation for real wage growth is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in the quantity of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a contraction of employment in service industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the rising cost of capital accumulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the rate of productivity growth</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Real wage growth refers to the increase in the purchasing power of wages, which is often due to an increase in productivity. Therefore, the correct answer is 'an increase in the rate of productivity growth'.</div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : WAGES"}, {"id": "objective>Economics>2016>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the criticisms of the price mechanism is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">producers are sovereign</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it provides low degree of freedom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it widen inequitable gap</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumers are sovereign</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The price mechanism is a system where the forces of demand and supply determine the prices of commodities and the changes therein. It is the buyers and sellers who actually determine the price of a commodity. One of the criticisms of the price mechanism is that it widens the inequitable gap. This is because the price mechanism does not consider the income distribution of a society. It only considers the demand and supply of goods and services. Therefore, those who have more income can demand more goods and services, which can lead to higher prices, making it difficult for those with lower income to afford them. This widens the gap between the rich and the poor.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2016>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An isoquant lying above to the right of another represent</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a lower output level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">over capacity utilization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">constant returns to scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a higher output level</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An isoquant is a contour line drawn through the set of points at which the same quantity of output is produced while changing the quantities of two or more inputs. The isoquant lying above to the right of another represents a higher output level. This is because moving to the right and upwards on an isoquant map implies increasing the quantity of inputs used in the production process, which in turn leads to a higher level of output.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCTION FUNCTIONS & LAWS OF RETURNS"}, {"id": "objective>Economics>2016>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The precautionary demand for money is determined by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">general price level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the level of income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the level of savings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the rate of interest</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The precautionary demand for money is determined by the level of income. This is because the precautionary demand for money refers to the money held for unexpected expenses and emergencies. The higher the income, the more money people will hold for precautionary purposes.</div>", "topic": "MONEY : DEMAND FOR MONEY"}, {"id": "objective>Economics>2016>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main reason for low agricultural produce in West Africa is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high dependency ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the use of crude implements in farming process</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the presence of large-scale agro-allied industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">over dependence on agriculture for subsistence</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The use of crude implement in the process of farming has affected agricultural productivity in West Africa.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2016>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The effect of emigration on a country's population is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase in the growth rate of population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in dependency ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in the population</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in the population</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Emigration which is the act of leaving one's country for another will result in decline in the country's population.</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>2016>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A distinguishing characteristics of consumer co-operative society is that the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the minimum number of shareholders is 5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">members are the workers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">members are the owners</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the maximum number of shareholders is 20</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A consumer co-operative society is a type of co-operative that is owned and controlled by the people who use its products or services. Therefore, the distinguishing characteristic of a consumer co-operative society is that the members are the owners.</div>", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES"}, {"id": "objective>Economics>2016>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: 32, 18, 24, 17, 16, 32, 28, 68, 71 and 15, the mode of the distribution is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">56</div>", "<div style=\"font-family:Cambria;font-size:17px;\">32</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15</div>", "<div style=\"font-family:Cambria;font-size:17px;\">71</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mode in statistics is the number that appears most frequently in a data set. A set may have one mode, more than one mode, or no mode at all. In the given list, the number 32 appears twice, which is more frequent than any other number. Therefore, the mode of the distribution is 32.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2016>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> From the diagram above, the population that yields the highest income per head is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The population with the highest income per head is x since it has the maximum point.</div>", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION"}, {"id": "objective>Economics>2016>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a country can produce 20 units of commodity A or 10 units of commodity B, the Opportunity Cost of 1B is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10B</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30B</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5A</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Opportunity cost is a key concept in economics, and it's the cost of foregoing the next best alternative when making a decision. In this case, if a country can produce 20 units of commodity A or 10 units of commodity B, the opportunity cost of producing 1 unit of commodity B is the amount of commodity A that could have been produced with the same resources, which is 2 units of commodity A. Therefore, the opportunity cost of 1B is 2A.</div>", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE"}, {"id": "objective>Economics>2016>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the price of a commodity is fixed below equilibrium, this will lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">excess supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess demand</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Excess demand or shortage occurs when price is fixed below the equilibrium price (i.e maximum price). </div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2016>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the characteristics of oligopoly is the availability of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a single seller</div>", "<div style=\"font-family:Cambria;font-size:17px;\">many sellers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">few buyers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">few sellers</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Oligopoly is a market structure characterized by a small number of firms that dominate the market. Therefore, one of the key characteristics of an oligopoly is the presence of few sellers. In an oligopoly, each seller has significant market power.</div>", "topic": "MARKET STRUCTURE : OLIGOPOLY"}, {"id": "objective>Economics>2016>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The optimal range of output for a perfectly competitive firm is where </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">AC is lowest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC is falling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC is rising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AVC is lowest</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Profit is maximized (or a producer strikes his equilibrium) when two conditions are satisfied - (i) MR = MC, and (ii) MC is rising (or MC is greater than MR beyond the point of equilibrium output).</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2016>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Government deficit financing of a country wil lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in the economic output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a contraction in income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a reduction in the levels of employment</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> When a government runs a deficit (i.e., it spends more money than it collects in revenue), it often injects additional funds into the economy through various mechanisms, such as government spending on infrastructure projects, social programs, and public investments. This increased government spending can stimulate economic activity, boost demand for goods and services, and lead to an increase in economic output. It can potentially lead to higher employment levels and greater economic growth.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2016>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Find the median of the following set of data 35, 10, 14, 38, 15, 18, 22, 30 and 24</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">22</div>", "<div style=\"font-family:Cambria;font-size:17px;\">35</div>", "<div style=\"font-family:Cambria;font-size:17px;\">38</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Median value is arrived at by rearranging the numbers in ascending order, thus : 10, 14, 15, 18, 22, 24, 30, 35, 38.  <br/> Median = 22.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2016>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An economy in which both the public and private sectors contribute to economic growth is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capitalist economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mixed economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feudal economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">socialist economy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mixed economy involves both the public and private sectors. <br/> A mixed economy is variously defined as an economic system blending elements of market economies with elements of planned economies, free markets with state interventionism, or private enterprise with public enterprise. There is no single definition of a mixed economy, but rather two major definitions</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2016>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A fiscal policy instrument that can influence the demand pattern in an economy is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">government spending</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">income tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tariffs</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Government expenditure is a component of fiscal policy used to influence the demand pattern in an economy.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2016>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that FC = ₦500, VC = ₦1500, Q = 50 units. Find the average cost of the product</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦10</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦30</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦40</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦20</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">AC</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">TC<hr size=\"1\" />Q</td></tr></table></div>  <br/>  and TC = FC + VC  <br/> Hence <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">AC</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">FC + VC<hr size=\"1\" />Q</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">AC</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500 + 1500<hr size=\"1\" />50</td></tr></table></div>  <br/>  = ₦40</div>", "topic": "THE CONCEPT OF COST & REVENUE : THE CONCEPT OF REVENUE"}, {"id": "objective>Economics>2016>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The supply of beverages by firms in monopolistic competition is an example of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">joint supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">composite supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">competitive supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">derived demand</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Monopolistic competition is a type of imperfect competition such that many producers sell products that are differentiated from one another. Hence, the supply of beverages by firms in monopolistic competition is an example of competitive supply. Joint supply refers to a situation where a single process yields multiple products. Composite supply refers to a good that is supplied by more than one industry. Derived demand is a demand for a good or service that results from the demand for a different, or related, good or service.</div>", "topic": "MARKET STRUCTURE : MONOPOLISTIC COMPETITION"}, {"id": "objective>Economics>2016>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in demand without a corresponding change in supply will lead to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a decrease in equilibrium price and an increase in equilibrium quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in equilibrium price and quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in equilibrium price and quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in equilibrium price and a decrease in equilibrium quantity</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When demand increases without change in supply, there will be an increase in equilibrium price and quantity.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2016>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If CBN reduces money supply, the interest rate will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fluntuate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rise </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain unchanged</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the Central Bank of a country (in this case, CBN - Central Bank of Nigeria) reduces the money supply, it means there is less money in circulation. This makes money more scarce and therefore more valuable. As a result, banks and other financial institutions increase the interest rate they charge for loans. This is because the cost of borrowing money increases when money is scarce. Therefore, when CBN reduces money supply, the interest rate will rise.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>2016>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the theory of production, a producer is at equilibrium at a point where </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">isocost is tangent to the marginal revenue </div>", "<div style=\"font-family:Cambria;font-size:17px;\">isocost is above the isoquant curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isoquant is below the isocost curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isoquant is tangent to the isocost curve</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the theory of production, a producer is at equilibrium at a point where the isoquant is tangent to the isocost curve. The isoquant curve represents all combinations of inputs that yield the same level of output. The isocost curve represents all combinations of inputs that cost the same amount. When these two curves are tangent, it means the producer is producing a given level of output at the lowest possible cost, which is the condition for equilibrium.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCERS EQUILIBRIUM"}, {"id": "objective>Economics>2016>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A component of fiscal policy is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">interest rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash reserve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">taxation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fiscal policy is the use of government revenue collection (taxation) and expenditure to influence a country's economy. The other options: interest rate, bank rate, and cash reserve are components of monetary policy, not fiscal policy.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2016>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An advantage of a public limited liability company is that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">management is separated from its shareholders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shares are easily transferred</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it has operational confidentiality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it has powerful trade union</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A public limited liability company is a company that has sold its shares to the public and has limited liability. One of its advantages is that its shares are easily transferred. The other options do not necessarily apply to all public limited liability companies.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>2016>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The deregulation of the petroleum sector in Nigeria will bring about </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">efficiency in pricing and distribution of the products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an end to the importation of fuel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an end to foreign firms' dominance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixing appropriate production quotas</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deregulation will help to promote efficiency in pricing and distribution of the products as it limits the activities of the government.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>2016>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the assumptions of the cardinalist approach is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diminishing marginal rate of substitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consistency and transitivity of choice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">total utility depends on the quantity of the commodities consumed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unstable marginal utility of money</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cardinalist approach assumes that the total utility of a particular commodity depends on the quantity of that commodity consumed.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT"}, {"id": "objective>Economics>2016>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An inflation that co-exists with high rate of unemployment is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">demand-pull inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hyperinflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stagflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost-push inflation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Stagflation is an economic condition where high inflation coexists with high unemployment and stagnant demand in a country's economy. It is a difficult economic condition as it's hard to fight both inflation and unemployment simultaneously as the policy to fight inflation can increase unemployment and vice versa.</div>", "topic": "INFLATION & DEFLATION : TYPES"}, {"id": "objective>Economics>2016>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A condition in which official and autonomous exchange rates coexist is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dual exchange rate system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">multiple exchange rate system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market determined exchanged rate system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">managed floating rate system</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A condition of official & autonomous exchange rate occurring together is called \"Dual exchange rate system\".</div>", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE"}];
